const btn = ({ children, onClick, variant = "primary", style = {}, disabled = false }) => {
  const variants = {
    primary: { background: "#3b82f6", color: "#fff", border: "none" },
    danger: { background: "#ef4444", color: "#fff", border: "none" },
    ghost: { background: "transparent", color: "#3b82f6", border: "1.5px solid #3b82f6" },
  };
  return (
    <button onClick={onClick} disabled={disabled} style={{
      ...variants[variant], padding: "10px 22px", borderRadius: 10, fontSize: 14, fontWeight: 600,
      cursor: disabled ? "not-allowed" : "pointer", opacity: disabled ? 0.6 : 1,
      display: "inline-flex", alignItems: "center", gap: 8, fontFamily: "inherit", ...style
    }}>
      {children}
    </button>
  );
};

export default btn;
